async def cmd_start(update: Update, context: ContextTypes.DEFAULT_TYPE):
    chat_id = update.effective_chat.id
    u = get_user(chat_id)
    sub = is_subscribed(chat_id)

    # Already registered and active
    if u and u.get("email") and sub:
        f = get_filters(chat_id)
        mr = int(f["min_rooms"]); xr = int(f["max_rooms"])
        mp = int(f["min_price"]); xp = int(f["max_price"])
        paid  = u.get("paid_until","")[:10]  if u.get("paid_until")  else ""
        trial = u.get("trial_until","")[:10] if u.get("trial_until") else ""
        expires = paid if paid and paid < "2090" else trial
        text = ("🏠 SAGA Apartment Bot\n\n"
                "✅ Бот активний\n"
                "🛏 Фільтр: " + str(mr) + "–" + str(xr) + " кімн. | 💶 €" + str(mp) + "–€" + str(xp) + "/мт\n"
                "📅 Підписка до: " + expires + "\n\n"
                "Бот сканує SAGA кожні " + str(SCAN_INTERVAL) + "с\n"
                "та перевіряє запрошення кожні " + str(INV_INTERVAL) + "с")
        await update.message.reply_text(text, reply_markup=kb_main(chat_id))

    # Registered but subscription expired
    elif u and u.get("email") and not sub:
        await update.message.reply_text(
            "⚠️ Підписка закінчилась!\n\nОнови щоб продовжити пошук квартир.",
            reply_markup=kb_main(chat_id))

    # New user — ask about Immomio account
    else:
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("✅ Так, є акаунт Immomio", callback_data="has_immomio")],
            [InlineKeyboardButton("❌ Немає акаунту", callback_data="no_immomio")],
            [InlineKeyboardButton("❓ Що таке Immomio?", callback_data="what_immomio")],
        ])
        await update.message.reply_text(
            "👋 Привіт! Я SAGA Apartment Bot\n\n"
            "Автоматично знаходжу квартири SAGA Hamburg,\n"
            "подаю заявки та приймаю запрошення на огляд.\n\n"
            "🆓 " + str(TRIAL_DAYS) + " днів безкоштовно\n"
            "💰 Далі " + SUBSCRIPTION_PRICE + "\n\n"
            "━━━━━━━━━━━━━━━━━━━━\n"
            "У тебе є акаунт на Immomio?",
            reply_markup=kb)

